const query = $('POST /support-query').first().json.body.query;
const customerId = $('POST /support-query').first().json.body.customer_id || 'anonymous';
const matches = $input.first().json.matches || [];

function keywordScore(text, queryTerms) {
  if (!text) return 0;
  const lowerText = text.toLowerCase();
  const lowerQuery = queryTerms.map(t => t.toLowerCase());
  let hits = 0;
  for (const term of lowerQuery) {
    if (lowerQuery.length <= 2) continue;
    if (lowerText.includes(term)) hits++;
  }
  return Math.min(hits / Math.max(lowerQuery.length, 1), 1.0);
}

const queryTerms = query.split(/\s+/).filter(t => t.length > 3);

const SEMANTIC_WEIGHT = 0.6;
const KEYWORD_WEIGHT = 0.4;
const CONFIDENCE_THRESHOLD = 0.45;

const scoredDocs = matches.map(m => {
  const semanticScore = m.score || 0;
  const docText = `${m.metadata.title || ''} ${m.metadata.content || m.metadata.text || ''}`.trim();
  const kwScore = keywordScore(docText, queryTerms);
  const hybridScore = (SEMANTIC_WEIGHT * semanticScore) + (KEYWORD_WEIGHT * kwScore);
  return {
    id: m.id,
    title: m.metadata.title || m.id,
    content: m.metadata.content || m.metadata.text || '',
    category: m.metadata.category || 'general',
    semanticScore: parseFloat(semanticScore.toFixed(4)),
    keywordScore: parseFloat(kwScore.toFixed(4)),
    hybridScore: parseFloat(hybridScore.toFixed(4))
  };
}).sort((a, b) => b.hybridScore - a.hybridScore);

const topDoc = scoredDocs[0] || null;
const confidence = topDoc ? topDoc.hybridScore : 0;
const canAutoResolve = confidence >= CONFIDENCE_THRESHOLD;
const topDocs = scoredDocs.slice(0, 3);

return [{ json: { query, customerId, scoredDocs, topDocs, topDoc, confidence, canAutoResolve, confidenceThreshold: CONFIDENCE_THRESHOLD } }];

const data = $input.first().json;

const contextDocs = data.topDocs
  .map((doc, i) => `[${i+1}] ${doc.title}\n${doc.content.slice(0, 600)}${doc.content.length > 600 ? '...' : ''}`)
  .join('\n\n');

const systemPrompt = `You are a helpful customer support assistant. Answer the customer's question accurately and concisely using only the provided knowledge base articles. If the articles don't fully answer the question, say so. Keep your answer under 200 words. End with a friendly closing.`;

const userMessage = `Customer question: ${data.query}\n\nRelevant knowledge base articles:\n${contextDocs}\n\nPlease answer based on the articles above.`;

return [{ json: { ...data, answerMessages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userMessage }] } }];

const hybridData = $('Hybrid Score + Confidence').first().json;
const gptResponse = $input.first().json;
const answer = gptResponse.choices[0].message.content;

return [{ json: { success: true, status: 'resolved', customer_id: hybridData.customerId, query: hybridData.query, answer, metadata: { confidence: hybridData.confidence, threshold: hybridData.confidenceThreshold, top_documents: hybridData.topDocs.map(d => ({ title: d.title, category: d.category, hybrid_score: d.hybridScore, semantic_score: d.semanticScore, keyword_score: d.keywordScore })) } } }];

const data = $input.first().json;

const ticketId = `TKT-${Date.now()}`;

const topCandidates = data.scoredDocs.slice(0, 5).map(d => ({
  title: d.title,
  category: d.category,
  hybrid_score: d.hybridScore
}));

const escalationPayload = {
  ticket_id: ticketId,
  customer_id: data.customerId,
  query: data.query,
  reason: `Low confidence (${data.confidence.toFixed(3)} < ${data.confidenceThreshold}) — could not find reliable answer`,
  top_candidates: topCandidates,
  priority: data.confidence < 0.4 ? 'high' : 'medium',
  created_at: new Date().toISOString()
};

return [{ json: { escalationPayload, ticketId, customerId: data.customerId, query: data.query, confidence: data.confidence } }];
